import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"上傳設定","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/upload/index.md","filePath":"zh-TW/upload/index.md","lastUpdated":1781962217000}'),o={name:"zh-TW/upload/index.md"};function t(d,a,h,n,s,c){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="上傳設定" tabindex="-1">上傳設定 <a class="header-anchor" href="#上傳設定" aria-label="Permalink to &quot;上傳設定&quot;">​</a></h1><p>這一章依照系統設定頁裡的實際渠道順序整理，方便你直接找到正在設定的儲存服務。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><ul><li>每個上傳渠道各自一頁，不把 13 個渠道混在同一篇裡。</li><li>截圖統一放在 <code>../../image/upload/渠道名/</code> 底下，文件會直接引用這些本機圖片。</li><li>這份繁中版以中文主稿為基礎，改成台灣常用詞與比較自然的說明方式。</li></ul><h2 id="渠道目錄" tabindex="-1">渠道目錄 <a class="header-anchor" href="#渠道目錄" aria-label="Permalink to &quot;渠道目錄&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="這一章會說明什麼" tabindex="-1">這一章會說明什麼 <a class="header-anchor" href="#這一章會說明什麼" aria-label="Permalink to &quot;這一章會說明什麼&quot;">​</a></h2><ul><li>每個上傳渠道要怎麼新增。</li><li>新增前需要先準備哪些金鑰、Token 或帳號資訊。</li><li>儲存後要怎麼確認渠道真的可以上傳。</li></ul><p>錯誤排查、容量策略和進階建議會依照各渠道狀況分開補充。</p>',9)])])}const p=e(o,[["render",t]]);export{f as __pageData,p as default};
